namespace sv_4d7de83920db40a0b060003ebc06f035.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@namespace sv_4d7de83920db40a0b060003ebc06f035.Components.JobApplication

<nav class="step-indicator" aria-label="Application progress">
    <ol class="step-list">
        @for (int i = 0; i < Steps.Count; i++)
        {
            var stepIndex = i;
            var stepName = Steps[i];
            var isCompleted = CompletedSteps.Contains(stepIndex);
            var isCurrent = stepIndex == CurrentStep;
            var cssClass = isCurrent ? "step current" : isCompleted ? "step completed" : "step future";

            <li class="@cssClass">
                @if (isCompleted && !isCurrent)
                {
                    <button class="step-button" @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                        <span class="step-icon">✓</span>
                        <span class="step-label">@stepName</span>
                    </button>
                }
                else
                {
                    <span class="step-content">
                        <span class="step-icon">@(stepIndex + 1)</span>
                        <span class="step-label">@stepName</span>
                    </span>
                }
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public List<string> Steps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

@namespace sv_4d7de83920db40a0b060003ebc06f035.Components.JobApplication

<div class="step-panel">
    <h2>Personal Information</h2>

    <div class="form-group">
        <label for="fullName">Full Name *</label>
        <input id="fullName" type="text" @bind="FullName" @bind:event="oninput" class="form-control" />
    </div>

    <div class="form-group">
        <label for="email">Email *</label>
        <input id="email" type="email" @bind="Email" @bind:event="oninput" class="form-control" />
    </div>

    <div class="form-group">
        <label for="phone">Phone *</label>
        <input id="phone" type="tel" @bind="Phone" @bind:event="oninput" class="form-control" />
    </div>

    <div class="form-group">
        <label for="address">Address *</label>
        <input id="address" type="text" @bind="Address" @bind:event="oninput" class="form-control" />
    </div>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message">@ErrorMessage</div>
    }

    <div class="step-actions">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
            @if (IsValidating)
            {
                <span>Validating...</span>
            }
            else
            {
                <span>Next</span>
            }
        </button>
    </div>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<PersonalInfoResult> OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(FullName))
        {
            ErrorMessage = "Full name is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Email))
        {
            ErrorMessage = "Email is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Phone))
        {
            ErrorMessage = "Phone is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "Address is required.";
            return;
        }

        if (ValidateEmail is not null)
        {
            IsValidating = true;
            StateHasChanged();

            var isValid = await ValidateEmail(Email);
            IsValidating = false;

            if (!isValid)
            {
                ErrorMessage = "The email address is not valid.";
                return;
            }
        }

        await OnNext.InvokeAsync(new PersonalInfoResult(FullName, Email, Phone, Address));
    }

    public record PersonalInfoResult(string FullName, string Email, string Phone, string Address);
}

@namespace sv_4d7de83920db40a0b060003ebc06f035.Components.JobApplication

<div class="work-entry-card">
    <div class="work-entry-header">
        <h4>Position @(Index + 1)</h4>
        @if (CanRemove)
        {
            <button class="btn btn-danger-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
        }
    </div>

    <div class="form-group">
        <label>Company Name *</label>
        <input type="text" value="@Entry.Company" @onchange="e => Update(e, nameof(Entry.Company))" class="form-control" />
    </div>

    <div class="form-group">
        <label>Job Title *</label>
        <input type="text" value="@Entry.Title" @onchange="e => Update(e, nameof(Entry.Title))" class="form-control" />
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Start Date *</label>
            <input type="date" value="@Entry.StartDate.ToString("yyyy-MM-dd")" @onchange="e => UpdateStartDate(e)" class="form-control" />
        </div>

        <div class="form-group">
            <label>End Date</label>
            <input type="date" value="@Entry.EndDate?.ToString("yyyy-MM-dd")" @onchange="e => UpdateEndDate(e)" class="form-control" disabled="@IsCurrent" />
            <label class="checkbox-label">
                <input type="checkbox" checked="@IsCurrent" @onchange="HandleCurrentToggle" />
                Currently working here
            </label>
        </div>
    </div>

    <div class="form-group">
        <label>Description</label>
        <textarea value="@Entry.Description" @onchange="e => Update(e, nameof(Entry.Description))" class="form-control" rows="3"></textarea>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
    [Parameter] public EventCallback<WorkEntryModel> OnChanged { get; set; }

    private bool IsCurrent => Entry.IsCurrent;

    private void Update(ChangeEventArgs e, string field)
    {
        var val = e.Value?.ToString() ?? "";
        var updated = field switch
        {
            nameof(Entry.Company) => Entry with { Company = val },
            nameof(Entry.Title) => Entry with { Title = val },
            nameof(Entry.Description) => Entry with { Description = val },
            _ => Entry
        };
        OnChanged.InvokeAsync(updated);
    }

    private void UpdateStartDate(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var date))
        {
            OnChanged.InvokeAsync(Entry with { StartDate = date });
        }
    }

    private void UpdateEndDate(ChangeEventArgs e)
    {
        DateTime? date = DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null;
        OnChanged.InvokeAsync(Entry with { EndDate = date });
    }

    private void HandleCurrentToggle(ChangeEventArgs e)
    {
        var isCurrent = (bool)(e.Value ?? false);
        OnChanged.InvokeAsync(Entry with { IsCurrent = isCurrent, EndDate = isCurrent ? null : Entry.EndDate });
    }

    public record WorkEntryModel
    {
        public string Company { get; init; } = "";
        public string Title { get; init; } = "";
        public DateTime StartDate { get; init; } = DateTime.Today;
        public DateTime? EndDate { get; init; }
        public bool IsCurrent { get; init; }
        public string Description { get; init; } = "";
    }
}

@namespace sv_4d7de83920db40a0b060003ebc06f035.Components.JobApplication

<div class="step-panel">
    <h2>Work History</h2>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="@Entries[index]"
                       Index="index"
                       CanRemove="@(Entries.Count > 1)"
                       OnRemove="() => RemoveEntry(index)"
                       OnChanged="model => UpdateEntry(index, model)" />
    }

    <button class="btn btn-secondary" @onclick="AddEntry">+ Add Another Position</button>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message">@ErrorMessage</div>
    }

    <div class="step-actions">
        <button class="btn btn-outline" @onclick="() => OnBack.InvokeAsync()">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public List<WorkEntryForm.WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public EventCallback<List<WorkEntryForm.WorkEntryModel>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    protected override void OnInitialized()
    {
        if (Entries.Count == 0)
        {
            Entries = new List<WorkEntryForm.WorkEntryModel> { new() };
        }
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryForm.WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private void UpdateEntry(int index, WorkEntryForm.WorkEntryModel model)
    {
        Entries[index] = model;
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ErrorMessage = "Each position requires at least a company name and job title.";
                return;
            }
        }
        await OnNext.InvokeAsync(Entries);
    }
}

@namespace sv_4d7de83920db40a0b060003ebc06f035.Components.JobApplication

<div class="reference-card">
    <div class="reference-header">
