@namespace sv_4d7de83920db40a0b060003ebc06f035.Components.JobApplication

<div class="step-panel">
    <h2>References</h2>
    <p class="step-description">Please provide 2–3 professional references.</p>

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Entry="@References[index]"
                       Index="index"
                       CanRemove="@(References.Count > 2)"
                       OnRemove="() => RemoveReference(index)"
                       OnChanged="model => UpdateReference(index, model)" />
    }

    @if (References.Count < 3)
    {
        <button class="btn btn-secondary" @onclick="AddReference">+ Add Reference</button>
    }

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message">@ErrorMessage</div>
    }

    <div class="step-actions">
        <button class="btn btn-outline" @onclick="() => OnBack.InvokeAsync()">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public List<ReferenceForm.ReferenceModel> References { get; set; } = new();
    [Parameter] public EventCallback<List<ReferenceForm.ReferenceModel>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    protected override void OnInitialized()
    {
        if (References.Count == 0)
        {
            References = new List<ReferenceForm.ReferenceModel> { new(), new() };
        }
    }

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceForm.ReferenceModel());
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private void UpdateReference(int index, ReferenceForm.ReferenceModel model)
    {
        References[index] = model;
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;
        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "All reference fields are required.";
                return;
            }
        }
        await OnNext.InvokeAsync(References);
    }
}

@namespace sv_4d7de83920db40a0b060003ebc06f035.Components.JobApplication

<div class="step-panel">
    <h2>Cover Letter</h2>

    <div class="form-group">
        <label for="coverLetter">Write your cover letter</label>
        <textarea id="coverLetter" @bind="CoverLetter" @bind:event="oninput"
                  class="form-control cover-letter-textarea" rows="12"
                  maxlength="2000"></textarea>
        <div class="char-count">@CoverLetter.Length / 2000 characters</div>
    </div>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message">@ErrorMessage</div>
    }

    <div class="step-actions">
        <button class="btn btn-outline" @onclick="() => OnBack.InvokeAsync()">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private async Task HandleNext()
    {
        ErrorMessage = null;
        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            ErrorMessage = "A cover letter is required.";
            return;
        }
        await OnNext.InvokeAsync(CoverLetter);
    }
}

@namespace sv_4d7de83920db40a0b060003ebc06f035.Components.JobApplication

<div class="step-panel">
    <h2>Review & Submit</h2>

    @if (IsSubmitted)
    {
        <div class="submission-confirmation">
            <h3>✓ Application Submitted Successfully!</h3>
            <p>Your application ID is: <strong>@ApplicationId</strong></p>
            <p>Thank you for applying. We will review your application and get back to you.</p>
        </div>
    }
    else
    {
        <section class="review-section">
            <div class="review-section-header">
                <h3>Personal Information</h3>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
            </div>
            <dl class="review-data">
                <dt>Name</dt><dd>@Personal.FullName</dd>
                <dt>Email</dt><dd>@Personal.Email</dd>
                <dt>Phone</dt><dd>@Personal.Phone</dd>
                <dt>Address</dt><dd>@Personal.Address</dd>
            </dl>
        </section>

        <section class="review-section">
            <div class="review-section-header">
                <h3>Work History</h3>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-work-entry">
                    <strong>@entry.Title</strong> at @entry.Company
                    <br />
                    <span class="text-muted">
                        @entry.StartDate.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p>@entry.Description</p>
                    }
                </div>
            }
        </section>

        <section class="review-section">
            <div class="review-section-header">
                <h3>References</h3>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var r in References)
            {
                <div class="review-reference">
                    <strong>@r.Name</strong> (@r.Relationship)
                    <br />@r.Email | @r.Phone
                </div>
            }
        </section>

        <section class="review-section">
            <div class="review-section-header">
                <h3>Cover Letter</h3>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
            </div>
            <p class="review-cover-letter">@CoverLetter</p>
        </section>

        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="error-message">@ErrorMessage</div>
        }

        <div class="step-actions">
            <button class="btn btn-outline" @onclick="() => OnBack.InvokeAsync()">Back</button>
            <button class="btn btn-primary btn-submit" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @if (IsSubmitting)
                {
                    <span>Submitting...</span>
                }
                else
                {
