@namespace sv_4d7de83920db40a0b060003ebc06f035.Components.JobApplication

<div class="work-entry-card">
    <div class="work-entry-header">
        <h4>Position @(Index + 1)</h4>
        @if (CanRemove)
        {
            <button class="btn btn-danger-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
        }
    </div>

    <div class="form-group">
        <label>Company Name *</label>
        <input type="text" value="@Entry.Company" @onchange="e => Update(e, nameof(Entry.Company))" class="form-control" />
    </div>

    <div class="form-group">
        <label>Job Title *</label>
        <input type="text" value="@Entry.Title" @onchange="e => Update(e, nameof(Entry.Title))" class="form-control" />
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Start Date *</label>
            <input type="date" value="@Entry.StartDate.ToString("yyyy-MM-dd")" @onchange="e => UpdateStartDate(e)" class="form-control" />
        </div>

        <div class="form-group">
            <label>End Date</label>
            <input type="date" value="@Entry.EndDate?.ToString("yyyy-MM-dd")" @onchange="e => UpdateEndDate(e)" class="form-control" disabled="@IsCurrent" />
            <label class="checkbox-label">
                <input type="checkbox" checked="@IsCurrent" @onchange="HandleCurrentToggle" />
                Currently working here
            </label>
        </div>
    </div>

    <div class="form-group">
        <label>Description</label>
        <textarea value="@Entry.Description" @onchange="e => Update(e, nameof(Entry.Description))" class="form-control" rows="3"></textarea>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
    [Parameter] public EventCallback<WorkEntryModel> OnChanged { get; set; }

    private bool IsCurrent => Entry.IsCurrent;

    private void Update(ChangeEventArgs e, string field)
    {
        var val = e.Value?.ToString() ?? "";
        var updated = field switch
        {
            nameof(Entry.Company) => Entry with { Company = val },
            nameof(Entry.Title) => Entry with { Title = val },
            nameof(Entry.Description) => Entry with { Description = val },
            _ => Entry
        };
        OnChanged.InvokeAsync(updated);
    }

    private void UpdateStartDate(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var date))
        {
            OnChanged.InvokeAsync(Entry with { StartDate = date });
        }
    }

    private void UpdateEndDate(ChangeEventArgs e)
    {
        DateTime? date = DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null;
        OnChanged.InvokeAsync(Entry with { EndDate = date });
    }

    private void HandleCurrentToggle(ChangeEventArgs e)
    {
        var isCurrent = (bool)(e.Value ?? false);
        OnChanged.InvokeAsync(Entry with { IsCurrent = isCurrent, EndDate = isCurrent ? null : Entry.EndDate });
    }

    public record WorkEntryModel
    {
        public string Company { get; init; } = "";
        public string Title { get; init; } = "";
        public DateTime StartDate { get; init; } = DateTime.Today;
        public DateTime? EndDate { get; init; }
        public bool IsCurrent { get; init; }
        public string Description { get; init; } = "";
    }
}

