@namespace sv_4d7de83920db40a0b060003ebc06f035.Components.JobApplication

<div class="step-panel">
    <h2>Work History</h2>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="@Entries[index]"
                       Index="index"
                       CanRemove="@(Entries.Count > 1)"
                       OnRemove="() => RemoveEntry(index)"
                       OnChanged="model => UpdateEntry(index, model)" />
    }

    <button class="btn btn-secondary" @onclick="AddEntry">+ Add Another Position</button>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message">@ErrorMessage</div>
    }

    <div class="step-actions">
        <button class="btn btn-outline" @onclick="() => OnBack.InvokeAsync()">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public List<WorkEntryForm.WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public EventCallback<List<WorkEntryForm.WorkEntryModel>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    protected override void OnInitialized()
    {
        if (Entries.Count == 0)
        {
            Entries = new List<WorkEntryForm.WorkEntryModel> { new() };
        }
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryForm.WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private void UpdateEntry(int index, WorkEntryForm.WorkEntryModel model)
    {
        Entries[index] = model;
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ErrorMessage = "Each position requires at least a company name and job title.";
                return;
            }
        }
