@namespace sv_4d7de83920db40a0b060003ebc06f035.Components.JobApplication

<div class="reference-card">
    <div class="reference-header">
        <h4>Reference @(Index + 1)</h4>
        @if (CanRemove)
        {
            <button class="btn btn-danger-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
        }
    </div>

    <div class="form-group">
        <label>Name *</label>
        <input type="text" value="@Entry.Name" @onchange="e => Update(e, nameof(Entry.Name))" class="form-control" />
    </div>

    <div class="form-group">
        <label>Relationship *</label>
        <input type="text" value="@Entry.Relationship" @onchange="e => Update(e, nameof(Entry.Relationship))" class="form-control" />
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Email *</label>
            <input type="email" value="@Entry.Email" @onchange="e => Update(e, nameof(Entry.Email))" class="form-control" />
        </div>

        <div class="form-group">
            <label>Phone *</label>
            <input type="tel" value="@Entry.Phone" @onchange="e => Update(e, nameof(Entry.Phone))" class="form-control" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
    [Parameter] public EventCallback<ReferenceModel> OnChanged { get; set; }

    private void Update(ChangeEventArgs e, string field)
    {
        var val = e.Value?.ToString() ?? "";
        var updated = field switch
        {
            nameof(Entry.Name) => Entry with { Name = val },
            nameof(Entry.Relationship) => Entry with { Relationship = val },
            nameof(Entry.Email) => Entry with { Email = val },
            nameof(Entry.Phone) => Entry with { Phone = val },
            _ => Entry
        };
        OnChanged.InvokeAsync(updated);
    }

    public record ReferenceModel
    {
        public string Name { get; init; } = "";
        public string Relationship { get; init; } = "";
        public string Email { get; init; } = "";
        public string Phone { get; init; } = "";
    }
}

