arguments.file_text:
@page "/apply"
@using sv_4d7de83920db40a0b060003ebc06f035.Components.JobApplication
@using sv_4d7de83920db40a0b060003ebc06f035.Models
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="application-container">
    <h1>Job Application</h1>

    <StepIndicator CurrentStep="@currentStep"
                   CompletedSteps="@completedSteps"
                   Steps="@stepNames"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep FullName="@personalFullName"
                              Email="@personalEmail"
                              Phone="@personalPhone"
                              Address="@personalAddress"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="HandlePersonalNext" />
            break;

        case 1:
            <WorkHistoryStep Entries="@workEntries"
                             OnNext="HandleWorkNext"
                             OnBack="GoBack" />
            break;

        case 2:
            <ReferencesStep References="@references"
                            OnNext="HandleReferencesNext"
                            OnBack="GoBack" />
            break;

        case 3:
            <CoverLetterStep CoverLetter="@coverLetter"
                             OnNext="HandleCoverLetterNext"
                             OnBack="GoBack" />
            break;

        case 4:
            <ReviewStep Personal="@GetPersonalResult()"
                        WorkEntries="@workEntries"
                        References="@references"
                        CoverLetter="@coverLetter"
                        OnEdit="GoToStep"
                        OnBack="GoBack"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep = 0;
    private HashSet<int> completedSteps = new();

    private readonly List<string> stepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    // Step 1 state
    private string personalFullName = "";
    private string personalEmail = "";
    private string personalPhone = "";
    private string personalAddress = "";

    // Step 2 state
    private List<WorkEntryForm.WorkEntryModel> workEntries = new() { new() };

    // Step 3 state
    private List<ReferenceForm.ReferenceModel> references = new() { new(), new() };

    // Step 4 state
    private string coverLetter = "";

    private void GoToStep(int step)
    {
        if (step <= currentStep || completedSteps.Contains(step) || completedSteps.Contains(step - 1))
        {
            currentStep = step;
        }
    }

    private void GoBack()
    {
        if (currentStep > 0) currentStep--;
    }

    private void HandlePersonalNext(PersonalInfoStep.PersonalInfoResult result)
    {
        personalFullName = result.FullName;
        personalEmail = result.Email;
        personalPhone = result.Phone;
        personalAddress = result.Address;
        completedSteps.Add(0);
        currentStep = 1;
    }

    private void HandleWorkNext(List<WorkEntryForm.WorkEntryModel> entries)
    {
        workEntries = entries;
        completedSteps.Add(1);
        currentStep = 2;
    }

    private void HandleReferencesNext(List<ReferenceForm.ReferenceModel> refs)
    {
        references = refs;
        completedSteps.Add(2);
        currentStep = 3;
    }

    private void HandleCoverLetterNext(string text)
    {
        coverLetter = text;
        completedSteps.Add(3);
        currentStep = 4;
    }

    private PersonalInfoStep.PersonalInfoResult GetPersonalResult()
        => new(personalFullName, personalEmail, personalPhone, personalAddress);

    private async Task<int> SubmitApplication()
    {
        var workHistory = new WorkHistory(
            workEntries.Select(e => new WorkEntry(
                e.Company, e.Title, e.StartDate, e.EndDate, e.Description
            )).ToList()
        );

        var refs = references.Select(r => new Reference(
            r.Name, r.Relationship, r.Email, r.Phone
        )).ToList();

        var personal = new PersonalInfo(personalFullName, personalEmail, personalPhone, personalAddress);
        var application = new JobApplication(personal, workHistory, refs, coverLetter);

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

.application-container {
    max-width: 800px;
    margin: 0 auto;
    padding: 2rem;
}

/* Step Indicator */
.step-indicator {
    margin-bottom: 2rem;
}

.step-list {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    gap: 0.25rem;
}

.step-list li {
    flex: 1;
    text-align: center;
    padding: 0.75rem 0.5rem;
    border-bottom: 3px solid #dee2e6;
    font-size: 0.875rem;
}

.step-list li.current {
    border-bottom-color: #0d6efd;
    font-weight: 600;
    color: #0d6efd;
}

.step-list li.completed {
    border-bottom-color: #198754;
    color: #198754;
}

.step-list li.future {
    color: #adb5bd;
}

.step-button {
    background: none;
    border: none;
    cursor: pointer;
    color: inherit;
    font: inherit;
    padding: 0;
}

.step-button:hover {
    text-decoration: underline;
}

.step-icon {
    display: block;
    font-size: 1.25rem;
    margin-bottom: 0.25rem;
}

.step-content {
    display: inline-block;
}

/* Step Panel */
.step-panel {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 2rem;
}

.step-panel h2 {
    margin-top: 0;
    margin-bottom: 1.5rem;
}

.step-description {
    color: #6c757d;
    margin-bottom: 1rem;
}

/* Form Elements */
.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.25rem;
    font-weight: 500;
}

.form-control {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 0.375rem;
    font-size: 1rem;
    box-sizing: border-box;
}

.form-control:focus {
    border-color: #86b7fe;
    outline: 0;
    box-shadow: 0 0 0 0.2rem rgba(13, 110, 253, 0.25);
}

.form-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1rem;
}

.checkbox-label {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    font-weight: normal;
    margin-top: 0.5rem;
}

/* Buttons */
.step-actions {
    display: flex;
    justify-content: space-between;
    margin-top: 2rem;
    padding-top: 1rem;
    border-top: 1px solid #dee2e6;
}

.btn {
    padding: 0.5rem 1.5rem;
    border-radius: 0.375rem;
    font-size: 1rem;
    cursor: pointer;
    border: 1px solid transparent;
}

.btn-primary {
    background-color: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

.btn-primary:hover {
    background-color: #0b5ed7;
}

.btn-primary:disabled {
    background-color: #6c9efc;
    cursor: not-allowed;
}

.btn-outline {
    background-color: #fff;
    color: #0d6efd;
    border-color: #0d6efd;
}

.btn-outline:hover {
    background-color: #e7f1ff;
}

.btn-secondary {
    background-color: #6c757d;
    color: #fff;
    border-color: #6c757d;
}

.btn-secondary:hover {
    background-color: #5c636a;
}

.btn-danger-sm {
    background-color: #dc3545;
