}

.step-list li.future {
    color: #adb5bd;
}

.step-button {
    background: none;
    border: none;
    cursor: pointer;
    color: inherit;
    font: inherit;
    padding: 0;
}

.step-button:hover {
    text-decoration: underline;
}

.step-icon {
    display: block;
    font-size: 1.25rem;
    margin-bottom: 0.25rem;
}

.step-content {
    display: inline-block;
}

/* Step Panel */
.step-panel {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 2rem;
}

.step-panel h2 {
    margin-top: 0;
    margin-bottom: 1.5rem;
}

.step-description {
    color: #6c757d;
    margin-bottom: 1rem;
}

/* Form Elements */
.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.25rem;
    font-weight: 500;
}

.form-control {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 0.375rem;
    font-size: 1rem;
    box-sizing: border-box;
}

.form-control:focus {
    border-color: #86b7fe;
    outline: 0;
    box-shadow: 0 0 0 0.2rem rgba(13, 110, 253, 0.25);
}

.form-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1rem;
}

.checkbox-label {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    font-weight: normal;
    margin-top: 0.5rem;
}

/* Buttons */
.step-actions {
    display: flex;
    justify-content: space-between;
    margin-top: 2rem;
    padding-top: 1rem;
    border-top: 1px solid #dee2e6;
}

.btn {
    padding: 0.5rem 1.5rem;
    border-radius: 0.375rem;
    font-size: 1rem;
    cursor: pointer;
    border: 1px solid transparent;
}

.btn-primary {
    background-color: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

.btn-primary:hover {
    background-color: #0b5ed7;
}

.btn-primary:disabled {
    background-color: #6c9efc;
    cursor: not-allowed;
}

.btn-outline {
    background-color: #fff;
    color: #0d6efd;
    border-color: #0d6efd;
}

.btn-outline:hover {
    background-color: #e7f1ff;
}

.btn-secondary {
    background-color: #6c757d;
    color: #fff;
    border-color: #6c757d;
}

.btn-secondary:hover {
    background-color: #5c636a;
}

.btn-danger-sm {
    background-color: #dc3545;
    color: #fff;
    border: none;
    padding: 0.25rem 0.75rem;
    border-radius: 0.25rem;
    font-size: 0.8rem;
    cursor: pointer;
}

.btn-link {
    background: none;
    border: none;
    color: #0d6efd;
    cursor: pointer;
    text-decoration: underline;
    font-size: 0.875rem;
    padding: 0;
}

/* Work Entry / Reference Cards */
.work-entry-card,
.reference-card {
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    padding: 1.5rem;
    margin-bottom: 1rem;
    background: #f8f9fa;
}

.work-entry-header,
.reference-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
}

.work-entry-header h4,
.reference-header h4 {
    margin: 0;
}

/* Cover Letter */
.cover-letter-textarea {
    resize: vertical;
    min-height: 200px;
}

.char-count {
    text-align: right;
    font-size: 0.875rem;
    color: #6c757d;
    margin-top: 0.25rem;
}

/* Review */
.review-section {
    margin-bottom: 1.5rem;
    padding-bottom: 1.5rem;
    border-bottom: 1px solid #dee2e6;
}

.review-section:last-of-type {
    border-bottom: none;
}

.review-section-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

.review-section-header h3 {
    margin: 0;
}

.review-data {
    display: grid;
    grid-template-columns: 120px 1fr;
    gap: 0.25rem 1rem;
}

.review-data dt {
    font-weight: 500;
    color: #6c757d;
}

.review-data dd {
    margin: 0;
}

.review-work-entry,
.review-reference {
    margin-bottom: 0.75rem;
    padding: 0.5rem 0;
}

.review-cover-letter {
    white-space: pre-wrap;
    background: #f8f9fa;
    padding: 1rem;
    border-radius: 0.375rem;
}

.text-muted {
    color: #6c757d;
    font-size: 0.875rem;
}

/* Error Message */
.error-message {
    color: #dc3545;
    background: #f8d7da;
    border: 1px solid #f5c6cb;
    padding: 0.75rem;
    border-radius: 0.375rem;
    margin-top: 1rem;
}

/* Submission Confirmation */
.submission-confirmation {
    text-align: center;
    padding: 2rem;
}

.submission-confirmation h3 {
    color: #198754;
}

.btn-submit {
    font-size: 1.1rem;
    padding: 0.75rem 2rem;
}

